code = """import json
import pandas as pd
import re
import os

# Get the data from previous query
business_data = var_functions.query_db:24

# Check what we have
print('Type:', type(business_data))
print('Length:', len(business_data) if hasattr(business_data, '__len__') else 'N/A')
if business_data and len(business_data) > 0:
    print('First item:', business_data[0])

# Process the data to find businesses that accept credit cards and extract categories
credit_card_businesses = []

for business in business_data:
    business_id = business.get('business_id', '')
    attributes = business.get('attributes', {})
    
    # Skip if attributes is None or 'None' string
    if not attributes or attributes == 'None':
        continue
    
    # Check if business accepts credit cards
    if isinstance(attributes, dict) and attributes.get('BusinessAcceptsCreditCards') == 'True':
        description = business.get('description', '')
        
        # Extract categories from description
        categories = []
        
        # Look for "services in" pattern
        match1 = re.search(r'services in ([^.]+)', description)
        if match1:
            text = match1.group(1).strip()
            for item in re.split(r',\s*|\sand\s', text):
                item = item.strip().strip('.')
                if item:
                    categories.append(item)
        
        # Look for "including" pattern
        elif 'including' in description:
            match2 = re.search(r'including ([^.]+)', description)
            if match2:
                text = match2.group(1).strip()
                for item in re.split(r',\s*|\sand\s', text):
                    item = item.strip().strip('.')
                    if item:
                        categories.append(item)
        
        # Look for "category of" pattern
        elif 'category of' in description:
            match3 = re.search(r"category of ['\"]([^'\"]+)['\"]", description)
            if match3:
                text = match3.group(1).strip()
                categories = [item.strip() for item in re.split(r',\s*', text) if item.strip()]
        
        # If no categories found, mark as Uncategorized
        if not categories:
            categories = ['Uncategorized']
        
        credit_card_businesses.append({
            'business_id': business_id,
            'categories': categories
        })

# Count businesses per category
category_counts = {}
for biz in credit_card_businesses:
    for category in biz['categories']:
        category_counts[category] = category_counts.get(category, 0) + 1

# Sort by count descending
sorted_categories = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)

print('Total businesses accepting credit cards:', len(credit_card_businesses))
print('Top categories:', sorted_categories[:5])

result = {
    'total_credit_card_businesses': len(credit_card_businesses),
    'top_categories': sorted_categories[:5],
    'sample_business': credit_card_businesses[0] if credit_card_businesses else None
}

print('__RESULT__:')
print(json.dumps(result))"""

